SELECT

FROM tb_wrk_dly_rpt
WHERE mbr_acct_idx = #{req.mbrAcctIdx}
  AND del_at IS NULL

    AND rpt_dt >= #{req.dateFrom}


    AND rpt_dt <= #{req.dateTo}


    AND sts = #{req.sts}


    AND (
        cntn ILIKE CONCAT('%', #{req.kwd}, '%')
        OR spcl_note ILIKE CONCAT('%', #{req.kwd}, '%')
    )

ORDER BY rpt_dt DESC, updated_at DESC
LIMIT #{req.size} OFFSET #{req.offset}

SELECT COUNT(*)
FROM tb_wrk_dly_rpt
WHERE mbr_acct_idx = #{req.mbrAcctIdx}
  AND del_at IS NULL

    AND rpt_dt >= #{req.dateFrom}


    AND rpt_dt <= #{req.dateTo}


    AND sts = #{req.sts}


    AND (
        cntn ILIKE CONCAT('%', #{req.kwd}, '%')
        OR spcl_note ILIKE CONCAT('%', #{req.kwd}, '%')
    )

SELECT EXISTS (
    SELECT 1
    FROM tb_wrk_dly_rpt
    WHERE mbr_acct_idx = #{mbrAcctIdx}
      AND rpt_dt = #{rptDt}
      AND del_at IS NULL

        AND wrk_dly_rpt_uuid != CAST(#{excludeUuid} AS UUID)

)

SELECT rpt_dt
FROM tb_wrk_dly_rpt
WHERE mbr_acct_idx = #{mbrAcctIdx}
  AND del_at IS NULL
  AND rpt_dt >= #{dateFrom}
  AND rpt_dt <= #{dateTo}
ORDER BY rpt_dt ASC

SELECT dr.wrk_dly_rpt_idx AS idx, dr.wrk_dly_rpt_uuid AS uuid, dr.mbr_acct_idx AS mbrAcctIdx, ma.mbr_acct_uuid AS mbrAcctUuid, ma.lgn_id, mp.nick_nm, dr.rpt_dt AS rptDt, dr.cntn, dr.sts, dr.spcl_note AS spclNote, dr.created_by AS createdBy, dr.updated_by AS updatedBy, dr.created_at AS createdAt, dr.updated_at AS updatedAt, dr.del_at AS delAt FROM tb_wrk_dly_rpt dr INNER JOIN tb_mbr_acct ma ON ma.mbr_acct_idx = dr.mbr_acct_idx LEFT JOIN tb_mbr_prfl mp ON mp.mbr_acct_idx = dr.mbr_acct_idx WHERE dr.del_at IS NULL AND ma.del_at IS NULL
AND ma.mbr_acct_uuid = CAST(#{req.mbrAcctUuid} AS UUID)
AND dr.rpt_dt >= #{req.dateFrom}
AND dr.rpt_dt <= #{req.dateTo}
AND dr.sts = #{req.sts}
AND ( dr.cntn ILIKE CONCAT('%', #{req.kwd}, '%') OR dr.spcl_note ILIKE CONCAT('%', #{req.kwd}, '%') OR ma.lgn_id ILIKE CONCAT('%', #{req.kwd}, '%') OR mp.nick_nm ILIKE CONCAT('%', #{req.kwd}, '%') )
ORDER BY dr.rpt_dt DESC, dr.updated_at DESC LIMIT #{req.size} OFFSET #{req.offset}

SELECT COUNT(*) FROM tb_wrk_dly_rpt dr INNER JOIN tb_mbr_acct ma ON ma.mbr_acct_idx = dr.mbr_acct_idx LEFT JOIN tb_mbr_prfl mp ON mp.mbr_acct_idx = dr.mbr_acct_idx WHERE dr.del_at IS NULL AND ma.del_at IS NULL
AND ma.mbr_acct_uuid = CAST(#{req.mbrAcctUuid} AS UUID)
AND dr.rpt_dt >= #{req.dateFrom}
AND dr.rpt_dt <= #{req.dateTo}
AND dr.sts = #{req.sts}
AND ( dr.cntn ILIKE CONCAT('%', #{req.kwd}, '%') OR dr.spcl_note ILIKE CONCAT('%', #{req.kwd}, '%') OR ma.lgn_id ILIKE CONCAT('%', #{req.kwd}, '%') OR mp.nick_nm ILIKE CONCAT('%', #{req.kwd}, '%') )

SELECT

FROM tb_wrk_dly_rpt
WHERE mbr_acct_idx = #{mbrAcctIdx}
  AND del_at IS NULL
  AND rpt_dt >= #{weekStartDate}
  AND rpt_dt <= #{weekEndDate}
ORDER BY rpt_dt ASC, updated_at DESC
